Функция ДостаточноТовараНаСкладе(НоменклатураСсылка, СкладСсылка, ТребуемоеКоличество)

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	ОстаткиТоваров.КоличествоОстаток КАК ТекущееКоличество
		|ИЗ
		|	РегистрНакопления.ОстаткиТоваров.Остатки(
		|		&МоментВремени,
		|		Склад = &Склад,
		|		Номенклатура = &Номенклатура) КАК ОстаткиТоваров";

	Запрос.УстановитьПараметр("МоментВремени", ТекущаяДата());
	Запрос.УстановитьПараметр("Склад", СкладСсылка);
	Запрос.УстановитьПараметр("Номенклатура", НоменклатураСсылка);

	Выборка = Запрос.Выполнить().Выбрать();

	Если Выборка.Следующий() Тогда
		ТекущееКоличество = Выборка.ТекущееКоличество;
		Возврат ТекущееКоличество >= ТребуемоеКоличество;
	Иначе
		Возврат Ложь; // Товара нет вообще
	КонецЕсли;

