Функция ABCКлассификация(НачалоПериода, КонецПериода)
    // Получаем список номенклатуры
    СписокНоменклатуры = РегистрНакопления.Продажи.Выбрать()
    .УстановитьПериод(НачалоПериода, КонецПериода)
    .ВыбратьИерархически()
    .ВыгрузитьКолонку("Номенклатура");

    // Сортируем номенклатуру по сумме оборота по убыванию
    СписокНоменклатуры.СортироватьПо("Сумма", Порядок.ПоУбыванию);

    // Получаем общий оборот за период
    ОбщийОборот = РегистрНакопления.Продажи.Выбрать()
    .УстановитьПериод(НачалоПериода, КонецПериода)
    .Сумма();

    // Инициализируем таблицу значений
    Таблица = Новый ТаблицаЗначений;
    Таблица.Колонки.Добавить("Номенклатура", Тип("СправочникСсылка.Номенклатура"));
    Таблица.Колонки.Добавить("Класс", Тип("Строка"));

    // Проходим по списку номенклатуры и присваиваем классы
    НакопленнаяДоля = 0;
    Для Каждого Номенклатура Из СписокНоменклатуры Цикл
        // Получаем сумму оборота для текущей номенклатуры
        СуммаОборота = РегистрНакопления.Продажи.Выбрать()
        .УстановитьПериод(НачалоПериода, КонецПериода)
        .УстановитьОтбор("Номенклатура", Номенклатура)
        .Сумма();

        // Присваиваем класс
        Если НакопленнаяДоля <= 0.8 Тогда
            Класс = "A";
        ИначеЕсли НакопленнаяДоля <= 0.95 Тогда
            Класс = "B";
        Иначе
            Класс = "C";
        КонецЕсли;

        // Добавляем строку в таблицу значений
        НоваяСтрока = Таблица.Добавить();
        НоваяСтрока.Номенклатура = Номенклатура;
        НоваяСтрока.Класс = Класс;

        // Обновляем накопленную долю
        НакопленнаяДоля = НакопленнаяДоля + СуммаОборота / ОбщийОборот;
    КонецЦикла;

    // Возвращаем таблицу значений
    Возврат Таблица;
