```bsl
Функция ПолучитьОстаткиТоваровНаСкладе(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено)

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	Результат.Колонки.Добавить("Остаток", Новый ОписаниеТипов("Число", , Новый КвалификаторыЧисла(15, 3)));

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	ТоварыНаСкладах.Номенклатура,
		|	ТоварыНаСкладах.ВНаличии
		|ИЗ
		|	РегистрНакопления.ТоварыНаСкладах КАК ТоварыНаСкладах
		|ГДЕ
		|	ТоварыНаСкладах.Склад = &Склад";

	Если МассивНоменклатуры.Количество() > 0 Тогда
		Запрос.Текст = Запрос.Текст +
			" И ТоварыНаСкладах.Номенклатура В (&МассивНоменклатуры)";
		Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	ИначеЕсли ЗначениеЗаполнено(ГруппаНоменклатуры) Тогда
		Запрос.Текст = Запрос.Текст +
			" И ТоварыНаСкладах.Номенклатура.Ссылка В (&ГруппаНоменклатуры)";

		ВыборкаГруппы = Новый ВыборкаИзДерева;
		ГруппаНоменклатуры.Выбрать(ВыборкаГруппы);

		МассивЭлементовГруппы = Новый Массив;
		Пока ВыборкаГруппы.Следующий() Цикл
			МассивЭлементовГруппы.Добавить(ВыборкаГруппы.Ссылка);
		КонецЦикла;

		Запрос.УстановитьПараметр("ГруппаНоменклатуры", МассивЭлементовГруппы);
	КонецЕсли;

	Запрос.УстановитьПараметр("Склад", Склад);

	Выборка = Запрос.Выполнить().Выбрать();

	Пока Выборка.Следующий() Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока.Номенклатура = Выборка.Номенклатура;
		НоваяСтрока.Остаток = Выборка.ВНаличии;
	КонецЦикла;

	Возврат Результат;

КонецФункции
