	|	И ПартииТоваровНаСкладахОстатки.КоличествоОстаток > 0
	|УПОРЯДОЧИТЬ ПО
	|	ДатаПартии";

	// Перебираем строки таблицы товаров
	Для каждого СтрокаТовара Из ТаблицаТоваров Цикл
		Номенклатура = СтрокаТовара.Номенклатура;
		ТребуемоеКоличество = СтрокаТовара.Количество;

