				РегистрПартий.Номенклатура КАК Номенклатура,
				РегистрПартий.Партия КАК Партия,
				СУММА(РегистрПартий.ОстатокКоличественный) КАК Остаток,
				СРЕДНЕЕ(РегистрПартий.Стоимость) КАК СредняяСтоимость
			ИЗ 
				РегистрНакопления.РегистраторПартииОстатков КАК РегистрПартий
			ГДЕ
				РегистрПартий.Склад = &Склад
				И РегистрПартий.Номенклатура = &Номенклатура
				И РегистрПартий.ОстатокКоличественный > 0

			СГРУППИРОВАТЬ ПО
				РегистрПартий.Номенклатура,
				РегистрПартий.Партия

			ИМЕЮЩИЕ
				СУММА(РегистрПартий.ОстатокКоличественный) > 0

			УПОРЯДОЧИТЬ ПО
				РегистрПартий.Партия";

		Запрос.УстановитьПараметр("Склад", Склад);
		Запрос.УстановитьПараметр("Номенклатура", СтрокаИзТаблицы.Номенклатура);

		ВыборкаОстатов = Запрос.Выполнить().Выбрать();

		Если НЕ ВыборкаОстатов.Следующий() Тогда
			Исключение "Недостаточно остатка по номенклатуре '"+СтрокаИзТаблицы.Номенклатура.Наименование+"'";
		КонецЕсли;

		ОстатокКСпсанию = СтрокаИзТаблицы.Количество;
		Пока ОстатокКСпсанию>0 И ВыборкаОстатов.Следующий() Цикл
