			НоваяСтрока.Номенклатура = ВыборкаОстатов.Номенклатура;
			НоваяСтрока.Партия = ВыборкаОстатов.Партия;
			Если ВыборкаОстатов.Остаток >= ОстатокКСпсанию Тогда
				НоваяСтрока.Количество = ОстатокКСпсанию;
				ОстатокКСпсанию=0; // Все списали
			Иначе
				НоваяСтрока.Количество = ВыборкаОстатов.Остаток;
				ОстатокКСпсанию -= ВыборкаОстатов.Остаток;
			КонецЕсли;
			НоваяСтрока.Стоимость = НоваяСтрока.Количество * ВыборкаОстатов.СредняяСтоимость;
		КонецЦикла;
	EndCycle;

	Возврат ИтоговаяТаблица;
