                ТаблицаРаспределения.ДобавитьСтроку();
                ТаблицаРаспределения.Номенклатура = строкаРезультата.Номенклатура;
                ТаблицаРаспределения.Партия = строкаРезультата.Партия;
                ТаблицаРаспределения.Количество = количествоИзПартии;
                ТаблицаРаспределения.Стимость = стоимостьИзПартии;

                остатокПартии += количествоИзПартии;
                общаяСумма += стоимостьИзПартии;

                Если остатокПартии >= строкаТаблицыТоваров.Количество Тогда
