Процедура ПересчитатьСуммы(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

    // Получение курса и кратности исходной валюты
    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |	КурсыВалют.Курс,
    |	КурсыВалют.Кратность
    |ИЗ
    |	РегистрСведений.КурсыВалют КАК КурсыВалют
    |ГДЕ
    |	КурсыВалют.Период = &Дата
    |	И КурсыВалют.Валюта = &Валюта";
    Запрос.УстановитьПараметр("Дата", ДатаКурса);
    Запрос.УстановитьПараметр("Валюта", ИсходнаяВалюта);
    Результат = Запрос.Выполнить().Выбрать();
    Если Результат.Следующий() Тогда
        КурсИсх = Результат.Курс;
        КратнИсх = Результат.Кратность;
    Иначе
        ВызватьИсключение "Курс для валюты " + ИсходнаяВалюта.Наименование + " не установлен на дату " + Формат(ДатаКурса, "ДЛФ=ДД");
    КонецЕсли;

    // Получение курса и кратности новой валюты
    Запрос.УстановитьПараметр("Валюта", НоваяВалюта);
    Результат = Запрос.Выполнить().Выбрать();
    Если Результат.Следующий() Тогда
        КурсНов = Результат.Курс;
        КратнНов = Результат.Кратность;
    Иначе
        ВызватьИсключение "Курс для валюты " + НоваяВалюта.Наименование + " не установлен на дату " + Формат(ДатаКурса, "ДЛФ=ДД");
    КонецЕсли;

    // Если валюты совпадают, пересчёт не требуется
    Если ИсходнаяВалюта = НоваяВалюта Тогда
        Возврат;
    КонецЕсли;

    // Расчёт коэффициента пересчёта (цена из исходной в новую)
    Коэффициент = (КурсИсх * КратнНов) / (КурсНов * КратнИсх);

    // Пересчёт строк табличной части
    Для Каждого Строка из Товары Цикл
        Строка.Цена = Строка.Цена * Коэффициент;
        Строка.Сумма = Строка.Цена * Строка.Количество;
    КонецЦикла;

КонецПроцедуры

