Процедура ПересчитатьСуммыПоВалюте(ТабличнаяЧастьТовары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса)

	// Получим курсы валют по дате
	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ РАЗРЕШЕННЫЕ
	|	КурсыВалют.Курс / КурсыВалют.Валюта.Кратность КАК КурсКБазовой,
	|	КурсыВалют.Валюта КАК Валюта
	|ИЗ
	|	РегистрСведений.КурсыВалют КАК КурсыВалют
	|ГДЕ
	|	КурсыВалют.Период <= &ДатаКурса
	|	И КурсыВалют.Валюта В (&МассивВалют)";

	Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);
	Запрос.УстановитьПараметр("МассивВалют", Новый Массив(ИсходнаяВалюта, НоваяВалюта));

	ВыборкаКурсов = Запрос.Выполнить().Выбрать();

	// Проверяем наличие курсов обеих валют
	КурсИсходной = Неопределено;
	КурсНовой = Неопределено;
	Пока ВыборкаКурсов.Следующий() Цикл
		Если ВыборкаКурсов.Валюта = ИсходнаяВалюта Тогда
			КурсИсходной = ВыборкаКурсов.КурсКБазовой;
		ИначеЕсли ВыборкаКурсов.Валюта = НоваяВалюта Тогда
			КурсНовой = ВыборкаКурсов.КурсКБазовой;
		КонецЕсли;
	EndDo;

	Если КурсИсходной = Неопределено Тогда
		Исключение "Отсутствует курс валюты '" + ИсходнаяВалюта.Наименование + "'";
	ИначеЕсли КурсНовой = Неопределено Тогда
		Исключение "Отсутствует курс валюты '" + НоваяВалюта.Наименование + "'";
	КонецЕсли;

	// Рассчитываем кросс-курс
	КроссКурс = КурсНовой / КурсИсходной;

	// Перебираем строки таблицы товаров и пересчитываем цену и сумму
	Для Каждого Строка Из ТабличнаяЧастьТовары Цикл
		Строка.Цена = Строка.Цена * КроссКурс;
		Строка.Сумма = Строка.Количество * Строка.Цена;
	EndDo;

