    ТаблицаОстатков.Колонки.Добавить("КонечныйОстаток", Тип("Число"));

    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ
         |  ДвиженияТоваров.Номенклатура,
         |  СУММА(ЕСЛИ(ДвиженияТоваров.Период <= &ДатаНачалаПериода, ДвиженияТоваров.Количество, 0)) КАК НачальныйОстаток,
         |  СУММА(ЕСЛИ(ДвиженияТоваров.Период >= &ДатаНачалаПериода И ДвиженияТоваров.Период <= &ДатаКонцаПериода И ДвиженияТоваров.Количество > 0, ДвиженияТоваров.Количество, 0)) КАК Приход,
         |  СУММА(ЕСЛИ(ДвиженияТоваров.Период >= &ДатаНачалаПериода И ДвиженияТоваров.Период <= &ДатаКонцаПериода И ДвиженияТоваров.Количество < 0, -ДвиженияТоваров.Количество, 0)) КАК Расход,
         |  СУММА(ЕСЛИ(ДвиженияТоваров.Период <= &ДатаКонцаПериода, ДвиженияТоваров.Количество, 0)) КАК КонечныйОстаток
         |ИЗ
         |  РегистрНакопления.ДвиженияТоваров КАК ДвиженияТоваров
         |ГДЕ
         |  ДвиженияТоваров.Период <= &ДатаКонцаПериода";

    Если НЕ Склад = Неопределено Тогда
        Запрос.Текст = Запрос.Текст + " И ДвиженияТоваров.Склад = &Склад";
    КонецЕсли;

    Запрос.Текст = Запрос.Текст + "
         |СГРУППИРОВАТЬ ПО
         |  ДвиженияТоваров.Номенклатура";

    Запрос.Параметры.Вставить("ДатаНачалаПериода", ДатаНачалаПериода);
    Запрос.Параметры.Вставить("ДатаКонцаПериода", ДатаКонцаПериода);
    Если НЕ Склад = Неопределено Тогда
        Запрос.Параметры.Вставить("Склад", Склад);
    КонецЕсли;

    РезультатЗапроса = Запрос.Выполнить();

    Если РезультатЗапроса.Пустой() Тогда
        Возврат ТаблицаОстатков;
    КонецЕсли;

    Для Каждого СтрокаЗапроса Из РезультатЗапроса Цикл
        НоваяСтрока = ТаблицаОстатков.Добавить();
        НоваяСтрока.Номенклатура = СтрокаЗапроса.Номенклатура;
