                И ДвиженияТоваров.Период <= &КонецПериода
                И ДвиженияТоваров.ВидДвижения = ЗНАЧЕНИЕ(ВидДвиженияНакопления.Расход)
                ТОГДА ДвиженияТоваров.Количество
            ИНАЧЕ 0
        КОНЕЦ) КАК Расход
    ИЗ
        РегистрНакопления.ДвиженияТоваров КАК ДвиженияТоваров
    ГДЕ
        (&Склад = НЕОПРЕДЕЛЕНО ИЛИ ДвиженияТоваров.Склад = &Склад)
    СГРУППИРОВАТЬ ПО
        ДвиженияТоваров.Номенклатура
    """;

    Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
    Запрос.УстановитьПараметр("КонецПериода", КонецПериода);
    Запрос.УстановитьПараметр("Склад", Склад);

    РезультатЗапроса = Запрос.Выполнить();
    Выборка = РезультатЗапроса.Выбрать();

    Пока Выборка.Следующий() Цикл
        СтрокаТаблицы = ТаблицаОстатков.Добавить();
        СтрокаТаблицы.Номенклатура = Выборка.Номенклатура;
        СтрокаТаблицы.НачальныйОстаток = Выборка.НачальныйОстаток;
        СтрокаТаблицы.Приход = Выборка.Приход;
        СтрокаТаблицы.Расход = Выборка.Расход;
        СтрокаТаблицы.КонечныйОстаток = Выборка.НачальныйОстаток + Выборка.Приход - Выборка.Расход;
    КонецЦикла;

    Возврат ТаблицаОстатков;
КонецФункции
