Функция ПолучитьОстаткиНоменклатуры(ДатаНачалаПериода, ДатаКонцаПериода, Склад = Неопределено)
	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура", Тип("СправочникСсылка.Номенклатура"));
	ТаблицаРезультат.Колонки.Добавить("НачальныйОстаток", Тип("Число"));
	ТаблицаРезультат.Колонки.Добавить("Приход", Тип("Число"));
	ТаблицаРезультат.Колонки.Добавить("Расход", Тип("Число"));
	ТаблицаРезультат.Колонки.Добавить("КонечныйОстаток", Тип("Число"));

	Запрос = Новый Запрос;
	ЗапросТекст = "ВЫБРАТЬ 
		Номенклатура.Ссылка КАК Номенклатура,
		ОстаткиНаСкладе.НачальныйОстаток КАК НачальныйОстаток,
		ВТПриход.ИтогоКоличество КАК Приход,
		ВТРасход.ИтогоКоличество КАК Расход
	ИЗ 
		Spr.Nomенклатура КАК Номенклатура
		ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.ОстаткиНаСкладе.Остатки(&ДатаНачалаПериода, , Номенклатура) КАК ОстаткиНаСкладе ПО
		ОстаткиНаСкладе.Номенклатура = Номенклатура.Ссылка
		ЛЕВОЕ СОЕДИНЕНИЕ 
			(ВЫБРАТЬ 
				Приход.Номенклатура,
				СУММА(Приход.Количество) КАК ИтогоКоличество
			ИЗ 
				Rgtn.DvжениеОстатковНаСкладе(&ДатаНачалаПериода, &ДатаКонцаПериода, , ) КАК Приход
			ГДЕ 
				Приход.ВидДвижения = ЗНАЧЕНИЕ(Перечисление.ВидыДвиженийПриходы)
				#Если ПустоеЗначение(&Склад, "") Тогда ""
				И Приход.Склад = &Склад
				#КонецЕсли
			СГРУППИРОВАТЬ ПО 
				Приход.Номенклатура) КАК ВТПриход ПО
		ВТПриход.Номенклатура = Номенклатура.Ссылка
		ЛЕВОЕ СОЕДИНЕНИЕ 
			(ВЫБРАТЬ 
				Расход.Номенклатура,
				СУММА(Расход.Количество) КАК ИтогоКоличество
			ИЗ 
				Rgtn.DvжениеОстатковНаСкладе(&ДатаНачалаПериода, &ДатаКонцаПериода, , ) КАК Расход
			ГДЕ 
				Расход.ВидДвижения = ЗНАЧЕНИЕ(Перечисление.ВидыДвиженийРасходы)
				#Если ПустоеЗначение(&Склад, "") Тогда ""
				И Расход.Склад = &Склад
				#КонецЕсли
			СГРУППИРОВАТЬ ПО 
				Расход.Номенклатура) КАК ВТРасход ПО
		ВТРасход.Номенклатура = Номенклатура.Ссылка";
	Запрос.Текст = ЗапросТекст;
	Запрос.УстановитьПараметр("ДатаНачалаПериода", ДатаНачалаПериода);
	Запрос.УстановитьПараметр("ДатаКонцаПериода", ДатаКонцаПериода);
	Если НЕ ПустоеЗначение(Склад, "") Тогда
		Запрос.УстановитьПараметр("Склад", Склад);
	КонецЕсли;
	РезультатЗапроса = Запрос.Выполнить().Выгрузить();

	Для Каждого Строка Из РезультатЗапоса Цикл
		НоваяСтрока = ТаблицаРезультат.Добавить();
		НоваяСтрока.Номенклатура = Строка.Номенклатура;
		НоваяСтрока.НачальныйОстаток = Строка.НачальныйОстаток;
		НоваяСтрока.Приход = Строка.Приход;
		НоваяСтрока.Расход = Строка.Расход;
		НоваяСтрока.КонечныйОстаток = НоваяСтрока.НачальныйОстаток + НоваяСтрока.Приход - НоваяСтрока.Расход;
	КонецЦикла;
	Возврат ТаблицаРезультат;
КонецФункции

Функция ПолучитьОстаткиНоменклатуры(НачалоПериода, КонецПериода, Склад) Экспорт
// Создаем таблицу значений для результата
ТаблицаРезультата = Новый ТаблицаЗначений;
ТаблицаРезультата.Колонки.Добавить("Номенклатура");
ТаблицаРезультута.Колонки.Добавить("НачальныйОстаток");
ТаблицаРезультута.Колонки.Добавить("Приход");
ТаблицаРезультута.Колонки.Добавить("Расход");
ТаблицаРезультута.Колонки.Добавить("КонечныйОстаток");

// Получаем список всех номенклатур
СписокНоменклатур = Справочник.Номенклатура.ПолучитьВыбранныеЭлементы();

Для Каждого Номенклатура Из СписокНоменклатур Цикл
Запрос = Новый Запрос;
Запрос.Текст =
"ВЫБРАТЬ
    Номенклатура.Код,
    Номенклатура.Наименование
ИЗ
    Справочник.Номенклатура КАК Номенклатура";

РезультатЗапроса = Запрос.Выполнить().Выбрать();

Если РезультатЗапроса.Следующий() Тогда
СтрокаТаблицы = ТаблицаРезультата.Добавить();
СтрокаТаблицы."Номенклатура" = РезультатЗапроса.Код + " - " + РезультатЗапроса.Наименование;

Запрос = Новый Запрос;
Запрос.Текст =
"ВЫБРАТЬ
    ОстатокНА.Склад,
    ОстатокНА.Остаток НА КАК НачальныйОстаток,
    СУММ(Документ.ПриходныйСкладскойДокумент.ПоступлениеТоваровУслуг.СуммаПоНоменклатуре) КАК Приход,
    СУММ(Документ.РасходныйСкладскойДокумент.СуммаПоНоменклатуре) КАК Расход
ИЗ
    РегистрНакопления.ОстаткиНА КАК ОстатокNA
    ЛЕВОЕ СОЕДИНЕНИЕ Документ.ПриходныйСкладскойДокумент КАК ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ
        ПО ОстатокNA.Склад = ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Склад И ОстатокNA.Номенклатура = ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Номенклатура
    ЛЕВОЕ СОЕДИНЕНИЕ Документ.РасходныйСкладскойДокумент КАК РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ
        ПО ОстатокNA.Склад = РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Склад И ОстатокNA.Номенклатура = РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Номенклатура
ГДЕ
    ОстатокNA.Склад = &Склад
И ОстатокNA.Период С <= &НачалоПериода
И ОстатокNA.Период К >= &КонецПериода
УПОРЯДОЧИТЬ ПО
    ОстатокNA.Номенклатура";

Если Параметр(Склад) <> Неопределено Тогда
Запрос.УстановитьПараметр("Склад", Склад);
КонецЕсли;

Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
Запрос.УстановитьПараметр("КонецПериода", КонецПериода);

РезультатЗапроса = Запрос.Выполнить();

Если РезультатЗапроса.Первый() Тогда
СтрокаТаблицы."НачальныйОстаток" = РезультатЗапроса.НачальныйОстаток;
СтрокаТаблицы."Приход" = РезультатЗапроса.Приход;
СтрокаТаблицы."Расход" = РезультатЗапроса.Расход;
СтрокаТаблицы."КонечныйОстаток" = СтрокаТаблицы."НачальныйОстаток" + СтрокаТаблицы."Приход" - СтрокаТаблицы."Расход";
Иначе
СтрокаТаблицы."НачальныйОстаток" = 0;
СтрокаТаблицы."Приход" = 0;
СтрокаТаблицы."Расход" = 0;
СтрокаТаблицы."КонечныйОстаток" = 0;
КонецЕсли;
КонецЕсли;
КонецЦикла;
Возврат ТаблицаРезультата;
