Функция СводТабличнойЧасти(ДокументСсылка) Экспорт
    ТаблицаСвода = Новый ТаблицаЗначений;
    ТаблицаСвода.Колонки.Добавить("Номенклатура");
    ТаблицаСвода.Колонки.Добавить("Количество", Тип("Число"));
    ТаблицаСвода.Колонки.Добавить("Сумма", Тип("Число"));

    // Получаем исходную табличную часть "Товары"
    Товары = ДокументСсылка.Товары;

    Для каждого СтрокаИзТоваров Из Товары Цикл
        НоваяСтрока = Неопределено;

        // Проверяем наличие уже существующей строки по данной номенклатуре
        Для каждого Стр Из ТаблицаСвода Цикл
            Если Стр.Номенклатура = СтрокаИзТоваров.Номенклатура Тогда
                НоваяСтрока = Стр;
                Прервать; 
            КонецЕсли;
        КонецЦикла;

        Если НоваяСтрока = Неопределено Тогда
            // Добавляем новую строку в сводную таблицу
            НоваяСтрока = ТаблицаСвода.Добавить();
            НоваяСтрока.Номенклатура = СтрокаИзТоваров.Номенклатура;
            НоваяСтрока.Количество = 0;
            НоваяСтрока.Сумма = 0;
        КонецЕсли;

        // Суммируем значения количества и суммы
        НоваяСтрока.Количество += СтрокаИзТоваров.Количество;
        НоваяСтрока.Сумма += СтрокаИзТоваров.Сумма;
    КонецЦикла;

    Возврат ТаблицаСвода;
КонецФункции
