Функция СводПоНоменклатуре(ДокСсылка) Экспорт
    ТаблицаРезультата = Новый ТаблицаЗначений;
    ТаблицаРезультата.Колонки.Добавить("Номенклатура");
    ТаблицаРезультата.Колонки.Добавить("Количество");
    ТаблицаРезультата.Колонки.Добавить("Сумма");

    Для каждого Строка из ДокСсылка.Товары Цикл
        Если Не НайденСтрокаСТакойНоменклатуройВТаблице(ТаблицаРезультата, Строка.Номенклатура) Тогда
            НоваяСтрока = ТаблицаРезультата.Добавить();
            НоваяСтрока.Номенклатура = Строка.Номенклатура;
            НоваяСтрока.Количество = Строка.Количество;
            НоваяСтрока.Сумма = Строка.Сумма;
        И Иначе
            НайденнаяСтрока = НайтиСтрокуСТакойНоменклатуройВТаблице(ТаблицаРезультата, Строка.Номенклатура);
            НайденнаяСтрока.Количество += Строка.Количество;
            НайденнаяСтрока.Сумма += Строка.Сумма;
        КонецЕсли;
    КонецЦикла;

    Возврат ТаблицаРезультата;
КонецФункции

Функция НайденСтрокаСТакойНоменклатуройВТаблице(Таблица, Номенклатура) Экспорт
    Для Каждого Строка Из Таблица Цикл
        Если Строка.Номенклатура = Номенклатура Тогда
            Возврат Истина;
        КонецЕсли;
    КонецЦикла;

    Возврат Ложь;
КонецФункции

Функция НайтиСтрокуСТакойНоменклатуройВТаблице(Таблица, Номенклатура) Экспорт
    Для Каждого Строка Из Таблица Цикл
        Если Строка.Номенклатура = Номенклатура Тогда
            Возврат Строка;
        КонецЕсли;
    КонецЦикла;

    Возврат Неопределено;
КонецФункции
